import{_ as t,o,c as a,ae as i}from"./chunks/framework.DhtYoOpx.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"articles/interview/cache.md","filePath":"articles/interview/cache.md","lastUpdated":null}'),c={name:"articles/interview/cache.md"};function l(p,e,r,d,n,s){return o(),a("div",null,[...e[0]||(e[0]=[i('<h3 id="http缓存策略" tabindex="-1">http缓存策略 <a class="header-anchor" href="#http缓存策略" aria-label="Permalink to &quot;http缓存策略&quot;">​</a></h3><h4 id="_1-强缓存-http状态码为200" tabindex="-1">1.强缓存（http状态码为200） <a class="header-anchor" href="#_1-强缓存-http状态码为200" aria-label="Permalink to &quot;1.强缓存（http状态码为200）&quot;">​</a></h4><p>http中用来判断是否命中强缓存的字段为Expires和Cache-Control，Cache-Control优先级高于Expires。</p><ul><li><p>expires的值是一个绝对时间，可以看到上图中的时间点：2019年5月30号08:04:42，这代表：这个资源在这个时间点之前都可以直接从缓存中获取。</p></li><li><p>cache-control常见字段的含义：</p></li></ul><blockquote><p>public</p></blockquote><blockquote><blockquote><p>表明响应可以被任何对象（包括：发送请求的客户端，CDN等代理服务器，等等）缓存，即使是通常不可缓存的内容（例如，该响应没有max-age指令或Expires消息头）。</p></blockquote></blockquote><blockquote><p>private</p><blockquote><p>表明响应只能被单个用户缓存，不能作为共享缓存（即代理服务器不能缓存它）。私有缓存可以缓存响应内容。</p></blockquote></blockquote><blockquote><p>no-cache</p><blockquote><p>可以在本地进行缓存，但每次发请求时，都要向服务器进行验证，如果服务器允许，才能使用本地缓存（即：需要协商缓存）。</p></blockquote></blockquote><blockquote><p>no-store</p><blockquote><p>禁止缓存客户端请求或服务器响应的内容，每次都须重新请求服务器拿内容</p></blockquote></blockquote><blockquote><p>max-age</p><blockquote><p>设置缓存存储的最大周期，超过这个时间缓存被视为过期 (单位**：秒)，这是一个相对时间（单位：秒）如max-age=7200，这里代表资源的缓存在这个请求之后的2小时内都有效。</p></blockquote></blockquote><h4 id="_2-协商缓存-http状态码为200或者304" tabindex="-1">2.协商缓存（http状态码为200或者304） <a class="header-anchor" href="#_2-协商缓存-http状态码为200或者304" aria-label="Permalink to &quot;2.协商缓存（http状态码为200或者304）&quot;">​</a></h4><ul><li>Last-Modified / If-Modified-Since</li><li>Etag / If-None-Match</li></ul><p><strong>注意：Etag的优先级是高于 Last-Modified 的</strong></p><h5 id="关于last-modified-if-modified-since" tabindex="-1">关于Last-Modified / If-Modified-Since <a class="header-anchor" href="#关于last-modified-if-modified-since" aria-label="Permalink to &quot;关于Last-Modified / If-Modified-Since&quot;">​</a></h5><blockquote><p>当浏览器第一次访问一个资源的时候，服务器会在response header中返回一个Last-Modified，代表这个资源最后的修改时间，当浏览器再次访问这个资源的时候，会在request header中带上 If-Modified-Since，值为上次请求时服务器返回的 Last-Modified 的值，然后服务器根据资源上次修改的时间确认资源在这段期间内是否更改过，如果没有，则返回==304==，如果有，则返回==200==并返回最新的资源</p></blockquote><h5 id="关于etag-if-none-match" tabindex="-1">关于Etag / If-None-Match <a class="header-anchor" href="#关于etag-if-none-match" aria-label="Permalink to &quot;关于Etag / If-None-Match&quot;">​</a></h5><blockquote><p>Etag / If-None-Match 与 Last-Modified / If-Modified-Since的机制类似，不同的是，Etag是通过一个校验码来对比资源是否更改过的，而不是通过资源的修改时间。当一个资源修改时，其校验码也会更改。当浏览器请求资源时，服务器会返回一个Etag字段，然后浏览器下一次请求时，会带上 If-None-Match ，值为上次服务器返回的Etag的值，服务器经过校验码的对比后决定返回==200或304==。</p></blockquote><p><img src="https://img-blog.csdnimg.cn/20200729153225959.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L2xpeGlhb2xvbmcyNDAwMzU=,size_16,color_FFFFFF,t_70" alt="在这里插入图片描述"></p>',18)])])}const f=t(c,[["render",l]]);export{u as __pageData,f as default};
